<?php
 namespace App\Services; use App\Models\Currency; use App\Models\Setting; class CurrencyService { public static function getActiveCurrency() { return Currency::active()->first(); } public static function convertToActive($amount, $fromCurrencyId = null) { $v1 = self::getActiveCurrency(); if (!$v1) { return $amount; } if ($fromCurrencyId) { $v2 = Currency::find($fromCurrencyId); if ($v2) { $amount = $amount * $v2->exchange_rate; } } return $amount / $v1->exchange_rate; } public static function formatAmount($amount, $fromCurrencyId = null) { $v3 = self::convertToActive($amount, $fromCurrencyId); $v1 = self::getActiveCurrency(); if ($v1) { return $v1->symbol . number_format($v3, 2); } return number_format($v3, 2); } } 